THE CLAIM:
{
 "title": "One WiFi sensor forces EU radio security review, adds 2 quarters",
 "narrative": "The model assumes the smart PDU can start selling right away and win 1% of its market in Year 1. But if it ships with any radio, an EU cybersecurity rule in force since 1 August 2025 requires a notified body to certify it, adding a 4 to 6 month wait. That queue shortens the selling window from 12 months to 6 to 8, cutting the Year-1 number roughly in half.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Product ships with a radio, triggering the EU rule live since August 2025.",
   "refs": [
    "profile:Product",
    "profile:Stage"
   ]
  },
  {
   "step": "propagation",
   "text": "Access-control settings force notified-body review; late start loses Year-1 deals.",
   "refs": [
    "digest:refine-demand-discontinuity.prelet-pipeline-lockout#c0",
    "digest:refine-competitive-foreclosure.bundling-eliminates-bakeoffs-year1#c2",
    "ledger:obtainableFactor"
   ]
  },
  {
   "step": "model-impact",
   "text": "Shorter selling window cuts the 1% Year-1 share about in half.",
   "refs": [
    "ledger:obtainableFactor",
    "digest:obtainable-benchmark#c5",
    "digest:refine-execution-window.som-window-semantics-mismatch#c4"
   ]
  }
 ],
 "falsifier": "Proof the launch product is wired-only, or an assessment showing its access-control design needs only self-declaration with a certificate in hand before first shipment.",
 "category": "execution",
 "evidence": [
  {
   "title": "EU Harmonizes EN 18031 Standards",
   "sourceType": "industry-report",
   "publisher": "SGS",
   "date": "2025-02-01",
   "excerpt": "If applied in full, the EN 18031-X:2024 series of harmonized standards allow manufacturers to demonstrate regulatory compliance by offering self-declaration, thereby avoiding the involvement of a Notified Body. However, if a product does not fully comply... manufacturers must obtain certification via a Notified Body before placing their [products on the market].",
   "url": "https://www.sgs.com/en/news/2025/02/safeguards-02625-eu-harmonizes-en-18031-standards",
   "attached": true
  },
  {
   "title": "Cybersecurity in Europe (webinar)",
   "sourceType": "industry-report",
   "publisher": "Nemko",
   "date": "2025-02-25",
   "excerpt": "1 Aug 2025 cybersecurity is part of CE marking for wireless products (RED)... When using password, the option not to set password is not accepted... If no harmonized standard is used = Notified Body",
   "url": "https://www.nemko.com/hubfs/2025-02-25%20Webinar%20-%20for%20distribution.pdf",
   "attached": true
  },
  {
   "title": "EN 18031-1 General Cybersecurity Certification: Steps & Timeline",
   "sourceType": "industry-report",
   "publisher": "BlueAsia Labs",
   "date": "2025-12-23",
   "excerpt": "The 12-20 week process detailed here applies to products requiring notified body (NB) conformity assessment... many enterprises faced delays: no pre-testing leading to 1-month rework; incomplete documents causing 3-week audit holds; underestimated factory audit time missing launch windows.",
   "url": "https://www.blueasialabs.com/shouyehuandeng/en-18031-1-general-cybersecurity-certification-steps-amp-timeline",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

